import type { NordicRenderingServerContext } from './types';

import { AsyncLocalStorage } from 'node:async_hooks';

import { getTestContextScope } from '@nordic/core-context';
import { isTestEnv } from '@nordic/utils/validation';

import { throwContextNotInitializedError } from '../../common/error';

export const storage = new AsyncLocalStorage<NordicRenderingServerContext>();

export function getContext() {
  const context = storage.getStore();

  if (!__DEV__) {
    return context!;
  }

  if (isTestEnv()) {
    return getTestContextScope().r as NordicRenderingServerContext;
  }

  if (!context) {
    throwContextNotInitializedError();
  }

  return context;
}
